import React from 'react';
import { useParams } from 'react-router-dom';
import Header from '../components/Header';
import Footer from '../components/Footer';
import LoadingSpinner from '../components/LoadingSpinner';
import { useFetchProduct } from '../hooks/useFetchProducts';

const ProductPage = () => {
  const { productId } = useParams<{ productId: string }>();
  const { product, loading, error } = useFetchProduct(productId);

  if (loading) return <LoadingSpinner />;
  if (error) return <div className="text-red-500">Error loading product.</div>;

  return (
    <div>
      <Header />
      <main className="max-w-6xl mx-auto px-4 py-8">
        {product ? (
          <div className="flex flex-col md:flex-row gap-8">
            <div className="flex-1">
              <img src={product.image} alt={product.title} className="rounded-xl shadow-md" />
            </div>
            <div className="flex-1">
              <h1 className="text-3xl font-bold mb-4">{product.title}</h1>
              <p className="text-gray-400 mb-4">{product.description}</p>
              <p className="text-xl font-semibold mb-4">${product.price}</p>
              <button className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Add to Cart</button>
            </div>
          </div>
        ) : (
          <div className="text-gray-400">Product not found.</div>
        )}
      </main>
      <Footer />
    </div>
  );
};

export default ProductPage;

