import React from 'react';
import Header from '../components/Header';
import Footer from '../components/Footer';
import CartItem from '../components/CartItem';
import { useCart } from '../hooks/useCart';

const CartPage = () => {
  const { cartItems, total, removeItem, updateQuantity } = useCart();

  return (
    <div>
      <Header />
      <main className="max-w-6xl mx-auto px-4 py-8">
        <h1 className="text-3xl font-bold mb-4">Shopping Cart</h1>
        {cartItems.length > 0 ? (
          <div className="grid grid-cols-1 gap-6">
            {cartItems.map(item => (
              <CartItem key={item.id} item={item} onRemove={removeItem} onUpdateQuantity={updateQuantity} />
            ))}
            <div className="text-right">
              <p className="text-xl font-semibold">Total: ${total.toFixed(2)}</p>
              <button className="mt-4 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Proceed to Checkout</button>
            </div>
          </div>
        ) : (
          <div className="text-gray-400">Your cart is empty. Start shopping now!</div>
        )}
      </main>
      <Footer />
    </div>
  );
};

export default CartPage;
